### 2. Backend (Node.js + Express)

Create a file named `server.js`:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');
const cors = require('cors');

const app = express();

// Middleware
app.use(bodyParser.json());
app.use(cors());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/roommanagement', {
    useNewUrlParser: true,
    useUnifiedTopology: true
});

// Define Room Schema
const RoomSchema = new mongoose.Schema({
    name: String,
    capacity: Number,
    isAvailable: Boolean
});

const Room = mongoose.model('Room', RoomSchema);

// Routes
app.post('/rooms', async (req, res) => {
    const { name, capacity, isAvailable } = req.body;
    const room = new Room({ name, capacity, isAvailable });
    await room.save();
    res.send(room);
});

app.get('/rooms', async (req, res) => {
    const rooms = await Room.find({});
    res.send(rooms);
});

app.put('/rooms/:id', async (req, res) => {
    const { id } = req.params;
    const { name, capacity, isAvailable } = req.body;
    await Room.findByIdAndUpdate(id, { name, capacity, isAvailable }, { new: true });
    res.send(await Room.findById(id));
});

// Start Server
const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

